sql:
SELECT state, year
FROM homeless_data
WHERE count > 1000 AND measure = 'Sheltered Homeless';

SELECT COUNT(*)
FROM homeless_data
WHERE state = 'AK' AND year = 2010;

SELECT state, SUM(count) AS total_count
FROM homeless_data
GROUP BY state;

SELECT measure_name, description, sub_measures
FROM measures
ORDER BY measure_name;

SELECT state, SUM(count) AS total_homeless_count
FROM homeless_data
GROUP BY state;

SELECT coc_name, population
FROM coc
WHERE population = (
    SELECT MAX(population)
    FROM coc
);

SELECT state, count, rank
FROM (
    SELECT state, count, RANK() OVER (PARTITION BY state ORDER BY count DESC) AS rank
    FROM homeless_data
) AS subquery
WHERE rank <= 3;

SELECT population
FROM states
WHERE state_code = 'CA';

SELECT coc_name, SUM(number_of_shelters) AS total_ships
FROM coc
GROUP BY coc_name;

SELECT state, year
FROM homeless_data
WHERE count = (SELECT MAX(count) FROM homeless_data);

SELECT state, gender, count, sub_population
FROM homeless_data
WHERE data_id = 1 AND source_id = 0 AND year = 1;

external_knowledge:
- 'people without a home' refers to the homeless population;
- 'category' refers to different sub-populations within the homeless community;
- 'certain state' and 'specific year' require specifying the state and year, respectively.
